"use strict";const navToggler=document.querySelector(".nav__toggler"),navList=document.querySelector(".nav__list"),nav=document.querySelector(".nav"),header=document.querySelector(".header"),main=document.querySelector(".main");navToggler.addEventListener("click",(()=>{const t=navList.getBoundingClientRect().height;nav.classList.contains("nav-active")?(nav.classList.remove("nav-active"),main.style.transform="",navList.style.transform=`translateY(-${t}px)`):(nav.classList.add("nav-active"),navList.style.transform="translateY(0)")})),window.addEventListener("resize",(()=>{if(nav.classList.contains("nav-active")){const t=navList.getBoundingClientRect().height;main.style.transform=`translateY(${t}px)`}})),main.addEventListener("transitionend",(function(){nav.classList.contains("nav-active")||(this.style.transform="")})),window.addEventListener("DOMContentLoaded",(t=>{const e=document.querySelectorAll(".projects__tile"),n=["--slideInLeft","--slideInRight","--slideInTop","--slideInBottom"];e.forEach((t=>{let e=Math.floor(Math.random()*n.length),a=n[e];t.classList.add("projects__tile"+a)}))}));